namespace IO {

  const int IN_LEN = 1 << 18 | 1;

  static char buf[IN_LEN] , *s , *t;

  inline int Getchar( void ) { return s == t && ( t = ( s = buf ) + fread( buf , 1 , IN_LEN , stdin ) ) , s == t ? -1 : *s++; }

  template <class T> inline void read( T & x ) {

    static int c , f;

    for( c = Getchar() , f = 0 ; c < '0' || c > '9' ; c = Getchar() ) if( c == '-' ) f = 1;

    for( x = 0 ; c <= '9' && c >= '0' ; c = Getchar() ) x = x * 10 + c - 48;

    x = f ? -x : x;

  }

}using IO::read;

const int MAXN = 1e5 + 1;

typedef pair<int,int> pii;

set<int> E[MAXN];

map<pii,int> rem;

int n , f[MAXN];

queue<pii> Q;

pii get( int x , int y ) { if( x > y ) swap( x , y ); return make_pair( x , y ); }

int find( const int & x ) { return x == f[x] ? x : f[x] = find( f[x] ); }

int main( void ) {

  read( n );

  for( int i = 1 , u , v ; i < n ; ++i ) {

    read( u ) , read( v );

    ++rem[get( u , v )];

