#define MAXN 100006

using namespace std;

int n,fa[MAXN],u,v,top,p[MAXN];

map<int,int> h[MAXN];

set<int> e[MAXN];

queue<pair<int,int> > q;

void link(int u,int v)

{

	e[u].insert(v);

	e[v].insert(u);

	if(u>v) swap(u,v);

	++h[u][v];

	if(h[u][v]==2) q.push(make_pair(u,v));

	if(h[u][v]>2)

	{

		printf("NO");

		exit(0);

	}

}

void cut(int u,int v)

{

	e[u].erase(v);

	if(u>v) swap(u,v);

	h[u].erase(v);

}

int find(int x)

{

	if(x!=fa[x]) fa[x]=find(fa[x]);

	return fa[x];

}

int main()

{

	//freopen("bluered.in","r",stdin);

	//freopen("bluered.out","w",stdout);

	scanf("%d",&n);

	for(int i=1;i<=n;i++)

		fa[i]=i;

	for(int i=1;i<n;i++)

	{

		scanf("%d%d",&u,&v);

		link(u,v);

	}

	for(int i=1;i<n;i++)

	{

		scanf("%d%d",&u,&v);

		link(u,v);

	}

	for(int i=1;i<n;i++)

	{

		do

		{

			if(q.empty())

			{

				printf("NO");

				return 0;

			}

			u=q.front().first;

			v=q.front().second;

			u=find(u);

			v=find(v);

			q.pop();

		}while(u==v);

		if(e[u].size()>e[v].size()) swap(u,v);

		fa[u]=v;

		cut(v,u);

		top=0;		

		for(set<int>::iterator it=e[u].begin();it!=e[u].end();it++)

			p[++top]=*it;

		for(int i=1;i<=top;i++)

		{

			int x=p[i];

			x=find(x);

			if(x==v) continue;

			link(x,v);

			cut(x,u);

		}

		e[u].clear();

	}

	printf("YES");

}

